def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 3:
            base_score = ratio ** 5 - np.sqrt(ratio)
            penalty = 0
            for m in range(1, 5):
                penalty += ((ratio / m) ** 2) * ((-1) ** m)
            priorities[i] = base_score + penalty
        elif 2 < ratio <= 3:
            score = (ratio - 2) * 15
            for n in range(1, 4):
                mod_val = bin_capacity % (item + n)
                score += (mod_val / (item + n)) * (n * 0.15)
            if bin_capacity < item * 2.5:
                score *= 1.5
            priorities[i] = max(score, 0)
        elif 1 < ratio <= 2:
            score = (ratio - 1) ** 3 * 12
            for p in range(1, 6):
                if p % 2 == 0:
                    score += np.log1p(bin_capacity / (item + p)) * 0.2
                else:
                    score -= np.log1p(bin_capacity / (item + p)) * 0.1
            priorities[i] = max(score, 0)
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for q in range(1, 8):
                term = ((1 - ratio) ** q) / (q ** 3)
                if q % 3 == 0:
                    term *= 1.3
                elif q % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.9
                score += term
            if bin_capacity < item * 1.2:
                score *= 2.5
            elif bin_capacity > item * 4:
                score /= 3
            for r in range(1, 5):
                mod_ratio = (bin_capacity % (item + r)) / (item + r)
                if mod_ratio > 0.5:
                    score += mod_ratio * 0.2
                else:
                    score -= mod_ratio * 0.1
            if score < 0:
                score = 0
            priorities[i] = score
    return priorities
